// SPDX-License-Identifier: Apache-2.0
//
// Project Meridian — engine-agnostic client net core: FlatBuffers codec helpers
// (issue #95).
//
// The wire payloads are FlatBuffers tables (schema/net/auth.fbs IF-1,
// schema/net/world.fbs IF-2), generated by flatc — the SAME codegen authd/worldd
// and the bot use, so client↔server serialization agrees by construction.
//
// This header provides two things:
//   1. Template helpers (verify_and_get / finish_to_bytes) that apply the untrusted-
//      input discipline the whole codebase uses: NEVER GetRoot without first running
//      the FlatBuffers Verifier over the bytes. These are header-only (they need the
//      flatbuffers runtime; a consumer that uses them includes the generated header
//      for T).
//   2. Concrete, POD-in/POD-out encode/decode functions for the messages the client
//      actually sends/consumes (ClientHello IF-1; MovementIntent / MovementState /
//      Disconnect IF-2). These keep the generated FlatBuffers types OUT of the
//      public API so callers (and the test suite) round-trip through plain structs
//      without depending on flatc codegen at their call site.
//
// CLEAN-ROOM: from the .fbs contracts + the FlatBuffers public API. No GPL source
// consulted (CONTRIBUTING.md).

#ifndef MERIDIAN_CLIENTNET_CODEC_H
#define MERIDIAN_CLIENTNET_CODEC_H

#include <cstdint>
#include <optional>
#include <string>
#include <vector>

#include "meridian/clientnet/framing.h"  // Bytes

namespace meridian::clientnet::codec {

// ---------------------------------------------------------------------------
// IF-1 (auth.fbs) — ClientHello, the first frame the client sends to authd.
// ---------------------------------------------------------------------------
struct ClientHello {
    std::uint32_t build = 0;
    std::uint16_t proto_ver = 0;
};

Bytes encode_client_hello(const ClientHello& in);
std::optional<ClientHello> decode_client_hello(const Bytes& buf);

// ---------------------------------------------------------------------------
// IF-2 (world.fbs) — MovementIntent (C→S) and MovementState (S→C).
// ---------------------------------------------------------------------------
struct MovementIntent {
    std::uint32_t seq = 0;
    std::uint32_t state_flags = 0;
    float x = 0.0f, y = 0.0f, z = 0.0f;
    float orientation = 0.0f;
    std::uint64_t client_time_ms = 0;
};

Bytes encode_movement_intent(const MovementIntent& in);
std::optional<MovementIntent> decode_movement_intent(const Bytes& buf);

struct MovementState {
    std::uint64_t entity_guid = 0;
    std::uint32_t ack_seq = 0;
    std::uint32_t state_flags = 0;
    float x = 0.0f, y = 0.0f, z = 0.0f;
    float orientation = 0.0f;
    std::uint64_t server_time_ms = 0;
};

Bytes encode_movement_state(const MovementState& in);
std::optional<MovementState> decode_movement_state(const Bytes& buf);

// ---------------------------------------------------------------------------
// IF-2 (world.fbs) — Disconnect (S→C), the grant-reject / server-close payload.
// ---------------------------------------------------------------------------
struct Disconnect {
    std::uint16_t reason = 0;  // world.fbs DisconnectReason
    std::string message;
};

Bytes encode_disconnect(const Disconnect& in);
std::optional<Disconnect> decode_disconnect(const Bytes& buf);

// ---------------------------------------------------------------------------
// IF-2 (world.fbs) — the #87 AoI relay: EntityEnter / EntityUpdate / EntityLeave
// (all S→C). These are the frames a client renders OTHER players from: a session
// spawns/enters range (EntityEnter), moves (EntityUpdate), or leaves range
// (EntityLeave). This is the ONE shared decode both the GUI net path
// (net_thread_core / MeridianNetThread) and the headless client-world probe use to
// turn a relay frame into a position for the remote interpolator — the single
// source of truth for the client-side entity-relay codec (the bot's separate
// bot_core.capture_entity_frame mirrors the same schema).
//
// Positions carry the WIRE (Z-UP) frame from world.fbs: x/y = ground plane, z =
// height. The consumer maps to the render frame (the interpolator / Godot node).

// EntityEnter (world.fbs): a full spawn/enter snapshot. attrs are ignored at M0
// (D-11 placeholder carries none); guid + type + pose drive render, and the vitals
// block (#430/#431 HUD contract, UI-01) drives the unit frame. Vitals are additive
// FlatBuffers fields — a pre-#430 EntityEnter decodes them to 0 / empty.
struct EntityEnter {
    std::uint64_t entity_guid = 0;
    std::uint32_t type_id = 0;
    float x = 0.0f, y = 0.0f, z = 0.0f;  // wire coords (z = height)
    float orientation = 0.0f;
    std::uint8_t char_class = 0;  // M0-frozen class id (roster.h Class; #328) — the
                                  // client colors the placeholder capsule by class.
                                  // 0 = unset/unknown.
    // Vitals (#430 HUD contract): server-authoritative; the client DISPLAYS them.
    std::uint32_t health = 0;      // current health at entry
    std::uint32_t max_health = 0;  // health cap
    std::uint32_t power = 0;       // current secondary power at entry
    std::uint32_t max_power = 0;   // secondary-power cap (0 when power_type = NONE)
    std::uint8_t power_type = 0;   // world.fbs PowerType (0=NONE,1=MANA,2=ENERGY,3=RAGE)
    std::uint16_t level = 0;       // unit level (0 = unset/unknown)
    std::string name;              // display name for the unit frame (empty = unnamed)
};

Bytes encode_entity_enter(const EntityEnter& in);
std::optional<EntityEnter> decode_entity_enter(const Bytes& buf);

// VitalsUpdate (world.fbs, #430/#431): a unit's vitals changed — the HUD delta the
// server pushes to the subject's own client + every observer whenever combat / heal
// / death / level-up moves health/power/level (no full re-enter). `name` is NOT here
// (it does not change in-life; it rides EntityEnter). Server-authoritative — the
// client DISPLAYS these, never predicts them (Principle 1).
struct VitalsUpdate {
    std::uint64_t entity_guid = 0;
    std::uint32_t health = 0;      // current health after the change (0 = dead)
    std::uint32_t max_health = 0;  // health cap (may change on level-up)
    std::uint32_t power = 0;       // current secondary power after the change
    std::uint32_t max_power = 0;   // secondary-power cap (0 when power_type = NONE)
    std::uint8_t power_type = 0;   // world.fbs PowerType (0=NONE,1=MANA,2=ENERGY,3=RAGE)
    std::uint16_t level = 0;       // unit level after the change (level-up)
};

Bytes encode_vitals_update(const VitalsUpdate& in);
std::optional<VitalsUpdate> decode_vitals_update(const Bytes& buf);

// ---------------------------------------------------------------------------
// IF-2 (world.fbs) — PROGRESSION: XpGained (0x0020) and LevelUp (0x0021), both S→C
// (CHR-03, #531). The server awards XP and dings the character; the client only
// DISPLAYS the XP bar + level-up presentation — it never runs the XP curve or the
// stat-growth math (Principle 1 "server is law"). Symmetric POD encode/decode like the
// vitals block above (the client decodes; the encoders exist for test/mock symmetry).
// ---------------------------------------------------------------------------

// XP_GAINED (world.fbs XpGained): one XP award + the progress toward the next level.
// `xp_gained` is THIS award; `xp_total` is XP accumulated INTO the current level (resets
// on a level-up); `xp_to_next` is the threshold to reach the next level. `level` is the
// player's level at the time of the award. The client fills the XP bar to xp_total/xp_to_next.
struct XpGained {
    std::uint64_t player_guid = 0;
    std::uint32_t xp_gained = 0;   // this award
    std::uint16_t level = 0;       // level at the time of the award
    std::uint32_t xp_total = 0;    // XP into the current level (bar numerator)
    std::uint32_t xp_to_next = 0;  // XP required to reach the next level (bar denominator)
};

Bytes encode_xp_gained(const XpGained& in);  // test/mock symmetry (client decodes)
std::optional<XpGained> decode_xp_gained(const Bytes& buf);

// LEVEL_UP (world.fbs LevelUp): the player leveled up. Carries the old + new level and
// the stat growth applied from the level curve (the new health cap `max_health` and the
// new secondary-resource cap `max_resource`). The client plays a brief level-up
// presentation and reflects the raised caps in the player unit frame.
struct LevelUp {
    std::uint64_t player_guid = 0;
    std::uint16_t old_level = 0;
    std::uint16_t new_level = 0;
    std::uint32_t max_health = 0;    // new health cap after stat growth
    std::uint32_t max_resource = 0;  // new secondary-resource cap after stat growth
};

Bytes encode_level_up(const LevelUp& in);  // test/mock symmetry (client decodes)
std::optional<LevelUp> decode_level_up(const Bytes& buf);

// EntityUpdate (world.fbs): a delta. Position fields are OPTIONAL (a move delta
// carries them; an attribute-only delta would not), so each is flagged present.
struct EntityUpdate {
    std::uint64_t entity_guid = 0;
    bool has_x = false, has_y = false, has_z = false, has_orientation = false;
    float x = 0.0f, y = 0.0f, z = 0.0f;  // wire coords (z = height)
    float orientation = 0.0f;

    // True when the delta carried a position (any of x/y/z) — i.e. the peer moved.
    bool has_position() const { return has_x || has_y || has_z; }
};

// Encode a move delta (all position fields present — matches worldd's move relay).
Bytes encode_entity_update(const EntityUpdate& in);
std::optional<EntityUpdate> decode_entity_update(const Bytes& buf);

// EntityLeave (world.fbs): the peer left the client's AoI.
struct EntityLeave {
    std::uint64_t entity_guid = 0;
    std::uint16_t reason = 0;  // world.fbs LeaveReason
};

Bytes encode_entity_leave(const EntityLeave& in);
std::optional<EntityLeave> decode_entity_leave(const Bytes& buf);

// ---------------------------------------------------------------------------
// IF-2 (world.fbs) — COMBAT: ability use + GCD/cast prediction (M1 CMB-01, D-10,
// #432). The optimistic-GCD path (server SAD §3.3, client SAD §2.2/§3c): the client
// sends CAST_REQUEST on an ability press and predicts the GCD/cast start locally; the
// server ACCEPTS (CastStart) or REJECTS (CastFailed) within one RTT so the client
// confirms or ROLLS BACK (resyncing its GCD clock from CastFailed.gcd_remaining_ms).
// The attack-table roll (hit/crit/…) and damage/heal are SERVER-AUTHORITATIVE and
// NEVER predicted (Principle 1) — they arrive as CastResult.
//
// Enum fields ride as u16 ordinals (world.fbs CastFailReason / AttackOutcome) so this
// POD API carries no generated-enum dependency, exactly like the status fields above.
// ---------------------------------------------------------------------------

// CAST_REQUEST (C→S): use `ability_id` against `target_guid` (0 = self / no target;
// the server resolves the actual target legality). `client_time_ms` is ClockSync-keyed.
struct CastRequest {
    std::uint32_t ability_id = 0;
    std::uint64_t target_guid = 0;
    std::uint64_t client_time_ms = 0;
};
Bytes encode_cast_request(const CastRequest& in);
std::optional<CastRequest> decode_cast_request(const Bytes& buf);  // test/mock symmetry

// CAST_START (S→C): ACCEPT — the server validated the use and started the GCD / cast.
// `cast_ms` = 0 is an instant ability (a CastResult follows immediately); > 0 is a
// cast-time ability (the CastResult follows on cast completion).
struct CastStart {
    std::uint32_t ability_id = 0;
    std::uint32_t cast_ms = 0;
    std::uint64_t server_time_ms = 0;
};
Bytes encode_cast_start(const CastStart& in);  // test/mock symmetry (client decodes)
std::optional<CastStart> decode_cast_start(const Bytes& buf);

// CAST_FAILED (S→C): REJECT — the server refused the use. `reason` is world.fbs
// CastFailReason (0=UNKNOWN_ABILITY … 3=ON_GCD … 6=NO_TARGET … 9=OUT_OF_RANGE …
// 11=INTERRUPTED). `gcd_remaining_ms` is the authoritative GCD remainder the client
// resyncs its optimistic clock to (0 = no GCD → a clean rollback of a bad prediction).
struct CastFailed {
    std::uint32_t ability_id = 0;
    std::uint16_t reason = 0;  // CastFailReason
    std::uint32_t gcd_remaining_ms = 0;
};
Bytes encode_cast_failed(const CastFailed& in);  // test/mock symmetry (client decodes)
std::optional<CastFailed> decode_cast_failed(const Bytes& buf);

// CAST_RESULT (S→C): the server-authoritative resolution — the attack-table outcome
// and the damage/heal actually applied. `outcome` is world.fbs AttackOutcome
// (0=MISS,1=DODGE,2=PARRY,3=HIT,4=CRIT). NEVER predicted by the client.
struct CastResult {
    std::uint32_t ability_id = 0;
    std::uint64_t caster_guid = 0;
    std::uint64_t target_guid = 0;
    std::uint16_t outcome = 3;  // AttackOutcome (default HIT)
    std::uint32_t amount = 0;   // damage or heal applied (0 on miss/dodge/parry)
    bool is_heal = false;
    std::uint32_t target_health = 0;  // target health AFTER application
    bool target_dead = false;
    std::uint64_t server_time_ms = 0;
};
Bytes encode_cast_result(const CastResult& in);  // test/mock symmetry (client decodes)
std::optional<CastResult> decode_cast_result(const Bytes& buf);

// One KNOWN ability as the owning client sees it (a row of the spellbook / action bar,
// #457). All metadata is server-authoritative (read from the AbilityStore): `cast_ms` = 0
// is instant; `triggers_gcd` false means using it does NOT start the global cooldown (the
// action bar must not predict one); `resource_cost` is 0 when `resource_type` is NONE.
// `resource_type` is world.fbs AbilityResource (0=NONE,1=MANA,2=RAGE,3=ENERGY), carried
// as a u8 ordinal so this POD API has no generated-enum dependency (like the status fields).
struct KnownAbility {
    std::uint32_t ability_id = 0;
    std::uint32_t cast_ms = 0;
    bool triggers_gcd = true;
    std::uint8_t resource_type = 0;  // AbilityResource
    std::uint32_t resource_cost = 0;
    float range_m = 0.0f;
};

// KNOWN_ABILITIES (S→C, 0x3005): the character's known ability set (spellbook), pushed to
// the OWNING client at ENTER_WORLD and re-sent after a TRAINER_LEARN that grows the set,
// so the action bar (#456) seeds from the REAL learned abilities + their metadata. A fresh
// character enters with an EMPTY set (M1: no durable ability table). A DISPLAY projection.
struct KnownAbilities {
    std::vector<KnownAbility> abilities;
};
Bytes encode_known_abilities(const KnownAbilities& in);  // test/mock symmetry (client decodes)
std::optional<KnownAbilities> decode_known_abilities(const Bytes& buf);

// ---------------------------------------------------------------------------
// IF-2 (world.fbs) — DEATH / GHOST / CORPSE-RUN / RESURRECT (M1 — CMB-03, #359/#532).
// The client PRESENTS this server-authoritative loop and sends the two empty C→S
// intents; it never predicts the state. DEATH_STATE opens the overlay (corpse guid +
// the auto-release countdown); RELEASE_REQUEST is the early-release intent; GHOST_STATE
// enters the ghost presentation (graveyard + the corpse-run destination); RESURRECT_REQUEST
// is the resurrect-at-corpse intent; RESURRECT_RESULT is the typed outcome. `status` rides
// as a u16 ordinal (world.fbs ResurrectStatus{OK=0,NOT_DEAD=1,NOT_RELEASED=2,TOO_FAR=3}) so
// this POD API carries no generated-enum dependency, exactly like the other status fields.
// ---------------------------------------------------------------------------

// DEATH_STATE (S→C): you died. `killer_guid` 0 = environment/unknown. The corpse
// (`corpse_guid` at corpse_x/y/z, wire Z-up) is the corpse-run destination; the overlay
// counts down `auto_release_ms` to the server's auto-release to the graveyard.
struct DeathState {
    std::uint64_t victim_guid = 0;
    std::uint64_t killer_guid = 0;
    std::uint64_t corpse_guid = 0;
    float corpse_x = 0.0f;
    float corpse_y = 0.0f;
    float corpse_z = 0.0f;
    std::uint32_t auto_release_ms = 0;
};
Bytes encode_death_state(const DeathState& in);  // test/mock symmetry (client decodes)
std::optional<DeathState> decode_death_state(const Bytes& buf);

// GHOST_STATE (S→C): you were released and are now a ghost at the graveyard
// (graveyard_x/y/z, wire Z-up). Run back to `corpse_guid` (the corpse-run destination).
struct GhostState {
    std::uint64_t player_guid = 0;
    float graveyard_x = 0.0f;
    float graveyard_y = 0.0f;
    float graveyard_z = 0.0f;
    std::uint64_t corpse_guid = 0;
};
Bytes encode_ghost_state(const GhostState& in);  // test/mock symmetry (client decodes)
std::optional<GhostState> decode_ghost_state(const Bytes& buf);

// RESURRECT_RESULT (S→C): the typed resurrection outcome. `status` is world.fbs
// ResurrectStatus (0=OK,1=NOT_DEAD,2=NOT_RELEASED,3=TOO_FAR). On OK the player is alive
// with `health`/`max_health`; otherwise `health` is 0 and the reason is `status`.
struct ResurrectResult {
    std::uint64_t player_guid = 0;
    std::uint16_t status = 0;  // ResurrectStatus (default OK)
    std::uint32_t health = 0;
    std::uint32_t max_health = 0;
};
Bytes encode_resurrect_result(const ResurrectResult& in);  // test/mock symmetry (client decodes)
std::optional<ResurrectResult> decode_resurrect_result(const Bytes& buf);

// RELEASE_REQUEST / RESURRECT_REQUEST (C→S): empty tables acting on self. The client
// ENCODES these intents (early graveyard release; resurrect at the corpse once the
// corpse-run completes). The decoders exist only for test/mock symmetry.
Bytes encode_release_request();
std::optional<bool> decode_release_request(const Bytes& buf);  // test/mock symmetry
Bytes encode_resurrect_request();
std::optional<bool> decode_resurrect_request(const Bytes& buf);  // test/mock symmetry

// ---------------------------------------------------------------------------
// IF-2 (world.fbs) — character management (D-35 / #286) + server-authoritative
// enter-world (D-35 / #341), over the AUTHENTICATED world session (post-HandshakeOk).
// The client lists/creates/deletes its OWN account's characters (worldd scopes
// every op to the session's grant-derived account) and then ENTER_WORLDs one.
// Status fields are the world.fbs enum ordinals (kept as u16 so the codec has no
// generated-enum dependency): CharCreateStatus{OK=0,DUPLICATE_NAME=1,INVALID_NAME=2,
// INVALID_RACE=3,INVALID_CLASS=4,LIMIT_REACHED=5,INTERNAL=6},
// CharDeleteStatus{OK=0,REFUSED=1,INTERNAL=2}, EnterWorldStatus{OK=0,NOT_FOUND=1,
// NO_CHARACTER=2,INTERNAL=3}.
// ---------------------------------------------------------------------------

// One roster row (world.fbs CharListEntry).
struct CharSummary {
    std::uint64_t character_id = 0;
    std::string name;
    std::uint8_t race = 0;
    std::uint8_t char_class = 0;
    std::uint16_t level = 0;
};

// CHAR_LIST_REQUEST carries no fields (the account is the session's).
Bytes encode_char_list_request();

// CHAR_LIST_RESPONSE — the account's roster (0 or 1 at M0, #329) + a typed status
// (world.fbs CharListStatus{OK=0, INTERNAL=1}). status=INTERNAL means the roster
// could NOT be read (server/DB fault, #479) — `characters` is empty but this is a
// LOAD FAILURE, not "zero characters": char-select must render a retry/error state
// rather than "no characters yet". An old-format buffer decodes as OK (default).
struct CharListResponse {
    std::vector<CharSummary> characters;
    std::uint16_t status = 0;  // CharListStatus: 0 OK, 1 INTERNAL
};
std::optional<CharListResponse> decode_char_list_response(const Bytes& buf);

// Per-character appearance (world.fbs Appearance, contract ① §5.2 / CHR-01 #435).
// hair/face/skin are 1-based preset ids from the race/sex customization catalog;
// version is the record version (only v1 at M1). Opaque-but-bounded: never gameplay-
// authoritative, so the server clamps out-of-range values rather than rejecting.
// morphs (§2.5 crowd budget) are 0 at M1 and so are not carried here.
struct Appearance {
    std::uint8_t version = 1;
    std::uint8_t hair = 1;
    std::uint8_t face = 1;
    std::uint8_t skin = 1;
};

// CHAR_CREATE_REQUEST — name + M0-frozen race/class + the chosen appearance set
// (CHR-01 #435). appearance is an APPENDED FlatBuffers field: omit it and the server
// falls back to its default {v1,1,1,1}; the client always sends the player's picks.
struct CharCreateRequest {
    std::string name;
    std::uint8_t race = 0;
    std::uint8_t char_class = 0;
    Appearance appearance;
};
Bytes encode_char_create_request(const CharCreateRequest& in);
// Decoder — the client never receives this C→S request, but the net-thread replay
// harness / codec tests decode it back to prove the appearance round-trips (symmetric
// with decode_movement_intent). Rejects garbage via verify-before-GetRoot.
std::optional<CharCreateRequest> decode_char_create_request(const Bytes& buf);

// CHAR_CREATE_RESPONSE — typed status + (on OK) the minted id.
struct CharCreateResponse {
    std::uint16_t status = 0;  // CharCreateStatus
    std::uint64_t character_id = 0;
};
std::optional<CharCreateResponse> decode_char_create_response(const Bytes& buf);

// CHAR_DELETE_REQUEST — one owned character id.
Bytes encode_char_delete_request(std::uint64_t character_id);

// CHAR_DELETE_RESPONSE — ok / refused.
struct CharDeleteResponse {
    std::uint16_t status = 0;  // CharDeleteStatus
};
std::optional<CharDeleteResponse> decode_char_delete_response(const Bytes& buf);

// ENTER_WORLD_REQUEST — spawn as this owned character.
Bytes encode_enter_world_request(std::uint64_t character_id);

// ENTER_WORLD_RESPONSE — typed enter result (OK spawns; else no spawn).
struct EnterWorldResponse {
    std::uint16_t status = 0;  // EnterWorldStatus
};
std::optional<EnterWorldResponse> decode_enter_world_response(const Bytes& buf);

// S→C response ENCODERS — the client never sends these, but mocks/tests (the net
// thread's replay harness, #97) build server frames through the SAME POD API rather
// than the generated types. Symmetric with encode_movement_state / encode_entity_*.
Bytes encode_char_list_response(const CharListResponse& in);
Bytes encode_char_create_response(const CharCreateResponse& in);
Bytes encode_char_delete_response(const CharDeleteResponse& in);
Bytes encode_enter_world_response(const EnterWorldResponse& in);

// ---------------------------------------------------------------------------
// IF-2 (world.fbs) — QUEST STATE (M1 QST-01, #371/#433) and NPC GOSSIP (M1
// NPC-01/02, #372/#433). The client is a pure DISPLAY of server-authoritative
// quest/gossip state (Principle 1 "server is law"): it ENCODES intents (accept a
// quest, turn one in, open gossip, request the log) and DECODES the typed results +
// snapshots the server pushes back. It never predicts quest state.
//
// Enum fields ride as u16/u8 ordinals (world.fbs QuestAcceptStatus / QuestTurnInStatus
// / QuestObjectiveType / GossipOptionKind) so this POD API carries no generated-enum
// dependency, exactly like the CharCreateStatus/EnterWorldStatus fields above.
// ---------------------------------------------------------------------------

// --- Gossip (0x52xx) --------------------------------------------------------

// GOSSIP_HELLO (C→S): open gossip on a targeted NPC entity guid. At M1 the guid maps
// 1:1 to the NPC template id (no NPC entities spawn yet — worldd's npc_store lookup).
struct GossipHello {
    std::uint64_t npc_guid = 0;
};
Bytes encode_gossip_hello(const GossipHello& in);
std::optional<GossipHello> decode_gossip_hello(const Bytes& buf);  // test/mock symmetry

// One computed gossip option (a menu row). `kind` is world.fbs GossipOptionKind
// (0=QUEST_AVAILABLE, 1=QUEST_IN_PROGRESS, 2=QUEST_COMPLETE, 3=VENDOR, 4=TRAINER);
// `target_id` is the quest id for the quest kinds, 0 for vendor/trainer.
struct GossipOption {
    std::uint16_t kind = 0;
    std::uint32_t target_id = 0;
};

// GOSSIP_MENU (S→C): the server-computed, state-gated option list for THIS player.
struct GossipMenu {
    std::uint64_t npc_guid = 0;
    std::vector<GossipOption> options;
};
Bytes encode_gossip_menu(const GossipMenu& in);  // test/mock symmetry (client decodes)
std::optional<GossipMenu> decode_gossip_menu(const Bytes& buf);

// --- Quest (0x40xx) ---------------------------------------------------------

// QUEST_ACCEPT (C→S): accept `quest_id` from the targeted `giver_guid` NPC.
struct QuestAccept {
    std::uint32_t quest_id = 0;
    std::uint64_t giver_guid = 0;
};
Bytes encode_quest_accept(const QuestAccept& in);
std::optional<QuestAccept> decode_quest_accept(const Bytes& buf);  // test/mock symmetry

// QUEST_ACCEPT_RESULT (S→C): typed accept outcome. `status` is world.fbs
// QuestAcceptStatus (0=OK; 1..7 = the typed rejections).
struct QuestAcceptResult {
    std::uint32_t quest_id = 0;
    std::uint16_t status = 0;
};
Bytes encode_quest_accept_result(const QuestAcceptResult& in);  // test/mock symmetry
std::optional<QuestAcceptResult> decode_quest_accept_result(const Bytes& buf);

// One objective's live state within a quest-log entry. `type` is world.fbs
// QuestObjectiveType (0=KILL,1=COLLECT,2=DELIVER,3=EXPLORE); `target_id` is the
// subject content id (creature/item/zone) per `type`.
struct QuestObjectiveState {
    std::uint16_t type = 0;
    std::uint32_t target_id = 0;
    std::uint16_t have = 0;
    std::uint16_t need = 0;
    bool complete = false;
};

// QUEST_PROGRESS (S→C): a single objective advanced (kill/collect/deliver/explore).
struct QuestProgress {
    std::uint32_t quest_id = 0;
    std::uint8_t objective_index = 0;
    std::uint16_t type = 0;  // QuestObjectiveType
    std::uint16_t have = 0;
    std::uint16_t need = 0;
    bool complete = false;
};
Bytes encode_quest_progress(const QuestProgress& in);  // test/mock symmetry
std::optional<QuestProgress> decode_quest_progress(const Bytes& buf);

// QUEST_TURN_IN (C→S): turn `quest_id` in at `turn_in_guid`. `choice_index` selects a
// reward for a choice-reward quest (>= 0), or -1 when the quest offers no choice.
struct QuestTurnIn {
    std::uint32_t quest_id = 0;
    std::uint64_t turn_in_guid = 0;
    std::int32_t choice_index = -1;
};
Bytes encode_quest_turn_in(const QuestTurnIn& in);
std::optional<QuestTurnIn> decode_quest_turn_in(const Bytes& buf);  // test/mock symmetry

// A reward item actually granted at turn-in (item template id + count).
struct QuestRewardItem {
    std::uint32_t item_id = 0;
    std::uint16_t count = 1;
};

// QUEST_TURN_IN_RESULT (S→C): typed turn-in outcome. On OK the rewards were granted;
// `status` is world.fbs QuestTurnInStatus (0=OK; 1..6 = the typed rejections).
struct QuestTurnInResult {
    std::uint32_t quest_id = 0;
    std::uint16_t status = 0;
    std::uint32_t reward_xp = 0;
    std::int64_t reward_money = 0;  // copper (ECO-01)
    std::vector<QuestRewardItem> reward_items;
    std::uint16_t new_level = 0;
};
Bytes encode_quest_turn_in_result(const QuestTurnInResult& in);  // test/mock symmetry
std::optional<QuestTurnInResult> decode_quest_turn_in_result(const Bytes& buf);

// One active quest in the log snapshot, including its REWARD PREVIEW (#443): the flat
// XP + copper, the always-granted `reward_items`, and the one-of `choice_items` (empty =
// no choice picker). This is what the client renders the turn-in offer + choice picker
// from BEFORE the player commits — the picked option rides QuestTurnIn.choice_index.
struct QuestLogEntry {
    std::uint32_t quest_id = 0;
    std::uint16_t level = 0;
    bool complete = false;
    std::vector<QuestObjectiveState> objectives;
    std::uint32_t reward_xp = 0;
    std::int64_t reward_money = 0;  // copper (ECO-01)
    std::vector<QuestRewardItem> reward_items;   // always-granted (preview)
    std::vector<QuestRewardItem> choice_items;   // one-of options (empty = no picker)
};

// QUEST_LOG (C↔S): C→S an EMPTY QuestLog is the "send me my log" request; S→C the
// populated QuestLog is the authoritative active-quest snapshot the client renders its
// quest log + tracker from. `encode_quest_log({})` builds the empty request body.
struct QuestLog {
    std::vector<QuestLogEntry> quests;
};
Bytes encode_quest_log(const QuestLog& in);  // C→S request (empty) + S→C mock symmetry
std::optional<QuestLog> decode_quest_log(const Bytes& buf);

// ---------------------------------------------------------------------------
// IF-2 (world.fbs) — CORPSE LOOTING (M1 ITM-02, #369/#441), VENDORS (M1 ECO-01,
// #370/#441), TRAINERS (M1 NPC-02, #372/#441). Server-authoritative throughout
// (Principle 1): the client issues intents (open loot, take a slot, buy/sell/buyback,
// learn) and DECODES the typed results/snapshots. It never rolls loot, prices an
// item, or decides learn eligibility — every value here is the server's.
//
// Enum fields ride as u16/u8 ordinals (world.fbs LootStatus / LootTakeStatus /
// VendorBuyStatus / VendorSellStatus / VendorBuybackStatus / TrainableState /
// TrainerLearnStatus) so this POD API carries no generated-enum dependency, exactly
// like the quest/gossip status fields above. All money is int64 COPPER (never FLOAT).
// ---------------------------------------------------------------------------

// --- Loot (0x5001..0x5006) --------------------------------------------------

// LOOT_REQUEST (C→S): open the loot window on a corpse (the dead creature's guid).
struct LootRequest {
    std::uint64_t corpse_guid = 0;
};
Bytes encode_loot_request(const LootRequest& in);
std::optional<LootRequest> decode_loot_request(const Bytes& buf);  // test/mock symmetry

// One lootable slot as THIS looter sees it (a row of the loot window). `quality` is
// the item's rarity tier (0=poor … 5=legendary) for the client's colour.
struct LootItem {
    std::uint32_t slot = 0;
    std::uint32_t item_template_id = 0;
    std::uint32_t count = 0;
    std::uint8_t quality = 0;
    bool quest_item = false;
};

// LOOT_RESPONSE (S→C): the money pile + the slots this looter may take. `status` is
// world.fbs LootStatus (0=OK; 1..4 = the typed pre-check rejections; empty items).
struct LootResponse {
    std::uint64_t corpse_guid = 0;
    std::uint16_t status = 0;  // LootStatus
    std::int64_t copper = 0;
    std::vector<LootItem> items;
};
Bytes encode_loot_response(const LootResponse& in);  // test/mock symmetry (client decodes)
std::optional<LootResponse> decode_loot_response(const Bytes& buf);

// LOOT_TAKE (C→S): take one slot from the corpse — or the money pile when `money` is
// true (then `slot` is ignored).
struct LootTake {
    std::uint64_t corpse_guid = 0;
    std::uint32_t slot = 0;
    bool money = false;
};
Bytes encode_loot_take(const LootTake& in);
std::optional<LootTake> decode_loot_take(const Bytes& buf);  // test/mock symmetry

// LOOT_RESULT (S→C): the outcome of a take. On OK an item take carries
// item_template_id + count (copper 0); a money take carries copper. `status` is
// world.fbs LootTakeStatus (0=OK; 1..7 = the typed rejections).
struct LootResult {
    std::uint64_t corpse_guid = 0;
    std::uint32_t slot = 0;
    std::uint16_t status = 0;  // LootTakeStatus
    std::uint32_t item_template_id = 0;
    std::uint32_t count = 0;
    std::int64_t copper = 0;
};
Bytes encode_loot_result(const LootResult& in);  // test/mock symmetry
std::optional<LootResult> decode_loot_result(const Bytes& buf);

// --- Inventory contents snapshot (0x5007 — ITM-01, #453/#471) ----------------

// One backpack slot as the owning client sees it (a row of the bags window). `slot` is
// the backpack GRID index (0-based); `quality` is the rarity tier (0=poor…5=legendary)
// for the client's colour; `binding` is the bind rule (0=none/1=on-pickup/2=on-equip).
struct InventoryItem {
    std::uint16_t slot = 0;
    std::uint32_t item_template_id = 0;
    std::uint32_t count = 0;
    std::uint8_t quality = 0;
    std::uint8_t binding = 0;
};

// INVENTORY_SNAPSHOT (S→C): the character's backpack contents + copper balance. Pushed to
// the OWNING client at ENTER_WORLD and after every server-authoritative inventory change
// (loot/vendor/quest-reward/GM .additem). `items` lists ONLY occupied slots (empty ones
// are omitted); `backpack_slots` is the grid capacity. A pure DISPLAY projection.
struct InventorySnapshot {
    std::int64_t money = 0;
    std::vector<InventoryItem> items;
    std::uint16_t backpack_slots = 0;
};
Bytes encode_inventory_snapshot(const InventorySnapshot& in);  // test/mock symmetry
std::optional<InventorySnapshot> decode_inventory_snapshot(const Bytes& buf);

// LOOT_RELEASE (C→S): close the loot window on a corpse.
struct LootRelease {
    std::uint64_t corpse_guid = 0;
};
Bytes encode_loot_release(const LootRelease& in);
std::optional<LootRelease> decode_loot_release(const Bytes& buf);  // test/mock symmetry

// LOOT_CLOSED (S→C): the loot window on a corpse closed (released / looted-out).
struct LootClosed {
    std::uint64_t corpse_guid = 0;
};
Bytes encode_loot_closed(const LootClosed& in);  // test/mock symmetry
std::optional<LootClosed> decode_loot_closed(const Bytes& buf);

// --- Vendor (0x5101..0x5106) ------------------------------------------------

// VENDOR_BUY_REQUEST (C→S): buy `quantity` of `item_template_id` from `vendor_id`.
// The price is the server's — NEVER sent by the client.
struct VendorBuyRequest {
    std::uint32_t vendor_id = 0;
    std::uint32_t item_template_id = 0;
    std::uint32_t quantity = 0;
};
Bytes encode_vendor_buy_request(const VendorBuyRequest& in);
std::optional<VendorBuyRequest> decode_vendor_buy_request(const Bytes& buf);  // mock

// VENDOR_BUY_RESULT (S→C): typed outcome. `status` is world.fbs VendorBuyStatus
// (0=OK; 1..7). On OK item_guid minted + total_price debited; `balance` is money after.
struct VendorBuyResult {
    std::uint16_t status = 0;  // VendorBuyStatus
    std::uint32_t vendor_id = 0;
    std::uint32_t item_template_id = 0;
    std::uint32_t quantity = 0;
    std::uint64_t item_guid = 0;
    std::int64_t total_price = 0;
    std::int64_t balance = 0;
};
Bytes encode_vendor_buy_result(const VendorBuyResult& in);  // test/mock symmetry
std::optional<VendorBuyResult> decode_vendor_buy_result(const Bytes& buf);

// VENDOR_SELL_REQUEST (C→S): sell `quantity` units of the item at `backpack_slot`.
struct VendorSellRequest {
    std::uint32_t vendor_id = 0;
    std::uint16_t backpack_slot = 0;
    std::uint32_t quantity = 0;
};
Bytes encode_vendor_sell_request(const VendorSellRequest& in);
std::optional<VendorSellRequest> decode_vendor_sell_request(const Bytes& buf);  // mock

// VENDOR_SELL_RESULT (S→C): typed outcome. `status` is world.fbs VendorSellStatus
// (0=OK; 1..5). On OK `total_credit` credited, the sold stack pushed onto the buyback
// queue at `buyback_slot`; `balance` is money after.
struct VendorSellResult {
    std::uint16_t status = 0;  // VendorSellStatus
    std::uint16_t backpack_slot = 0;
    std::uint32_t item_template_id = 0;
    std::uint32_t quantity = 0;
    std::int64_t total_credit = 0;
    std::int64_t balance = 0;
    std::uint16_t buyback_slot = 0;
};
Bytes encode_vendor_sell_result(const VendorSellResult& in);  // test/mock symmetry
std::optional<VendorSellResult> decode_vendor_sell_result(const Bytes& buf);

// VENDOR_BUYBACK_REQUEST (C→S): repurchase the item at `buyback_slot` of the queue.
struct VendorBuybackRequest {
    std::uint16_t buyback_slot = 0;
};
Bytes encode_vendor_buyback_request(const VendorBuybackRequest& in);
std::optional<VendorBuybackRequest> decode_vendor_buyback_request(const Bytes& buf);  // mock

// VENDOR_BUYBACK_RESULT (S→C): typed outcome. `status` is world.fbs VendorBuybackStatus
// (0=OK; 1..4). On OK the item is re-minted and `price` re-debited; `balance` after.
// `buyback_slot` ECHOES the request's slot (#453/#471) so the client drops that queue row
// without correlating against its own outstanding request.
struct VendorBuybackResult {
    std::uint16_t status = 0;  // VendorBuybackStatus
    std::uint32_t item_template_id = 0;
    std::uint32_t quantity = 0;
    std::uint64_t item_guid = 0;
    std::int64_t price = 0;
    std::int64_t balance = 0;
    std::uint16_t buyback_slot = 0;  // echoed queue slot that was repurchased (#453)
};
Bytes encode_vendor_buyback_result(const VendorBuybackResult& in);  // test/mock symmetry
std::optional<VendorBuybackResult> decode_vendor_buyback_result(const Bytes& buf);

// --- Vendor catalog push (0x5107 — ECO-01, #453/#471) -----------------------

// One for-sale listing as the client sees it (a row of the vendor buy window). `price` is
// the SERVER-COMPUTED buy price (catalog override or the template's buy price) — the buy
// path re-derives it (Principle 1). `quality` is the rarity tier for the client's colour;
// `stock` is remaining units, or -1 for unlimited (M1 vendors are unlimited).
struct VendorItem {
    std::uint32_t item_template_id = 0;
    std::int64_t price = 0;
    std::uint8_t quality = 0;
    std::int32_t stock = -1;
};

// VENDOR_LIST (S→C): a vendor's catalog for the client's buy window — the vendor id + its
// listed items with server-computed prices. Auto-pushed on GOSSIP_HELLO to a vendor NPC
// (like TRAINER_LIST; there is no C→S request). An unknown/empty vendor yields no items.
struct VendorList {
    std::uint32_t vendor_id = 0;
    std::vector<VendorItem> items;
};
Bytes encode_vendor_list(const VendorList& in);  // test/mock symmetry (client decodes)
std::optional<VendorList> decode_vendor_list(const Bytes& buf);

// --- Trainer (0x5203..0x5205) -----------------------------------------------

// One trainable ability as THIS player sees it (a row of the trainer window). All
// server-computed: `cost` is content copper, the gate is class/level, `state` is the
// player's eligibility (world.fbs TrainableState: 0=LEARNABLE, 1=ALREADY_KNOWN,
// 2=WRONG_CLASS, 3=LEVEL_TOO_LOW, 4=CANT_AFFORD).
struct TrainerListEntry {
    std::uint32_t ability_id = 0;
    std::int64_t cost = 0;
    std::uint8_t required_class = 0;
    std::uint16_t required_level = 0;
    std::uint16_t state = 0;  // TrainableState
};

// TRAINER_LIST (S→C): a trainer NPC's ability list for THIS player (pushed alongside
// GOSSIP_MENU on a GOSSIP_HELLO to a trainer NPC — there is no C→S request for it).
struct TrainerList {
    std::uint64_t npc_guid = 0;
    std::vector<TrainerListEntry> entries;
};
Bytes encode_trainer_list(const TrainerList& in);  // test/mock symmetry (client decodes)
std::optional<TrainerList> decode_trainer_list(const Bytes& buf);

// TRAINER_LEARN (C→S): learn one ability from a trainer NPC. The cost is NOT a field —
// it is the server's content value.
struct TrainerLearn {
    std::uint64_t npc_guid = 0;
    std::uint32_t ability_id = 0;
};
Bytes encode_trainer_learn(const TrainerLearn& in);
std::optional<TrainerLearn> decode_trainer_learn(const Bytes& buf);  // test/mock symmetry

// TRAINER_LEARN_RESULT (S→C): typed learn outcome. `status` is world.fbs
// TrainerLearnStatus (0=OK; 1..6). On OK `cost` was debited and `new_balance` is the
// balance after; on any rejection `new_balance` is the UNCHANGED balance.
struct TrainerLearnResult {
    std::uint64_t npc_guid = 0;
    std::uint32_t ability_id = 0;
    std::uint16_t status = 0;  // TrainerLearnStatus
    std::int64_t cost = 0;
    std::int64_t new_balance = 0;
};
Bytes encode_trainer_learn_result(const TrainerLearnResult& in);  // test/mock symmetry
std::optional<TrainerLearnResult> decode_trainer_learn_result(const Bytes& buf);

// ---------------------------------------------------------------------------
// IF-2 (world.fbs) — CHAT / SOCIAL (M1 SOC-01, #367/#434). The client sends ONE
// ChatMessage per line (the `channel` selects say/yell/whisper/zone routing); the
// server delivers lines back as ChatDeliver (incl. SYSTEM lines — sender_guid 0,
// sender_name "System" — for GM-command replies and the mute notice) and refuses a
// bad send with a typed ChatRejected. '.'-prefixed GM commands (.help/.tele) ride the
// SAME ChatMessage opcode; the server's System reply comes back as a ChatDeliver.
//
// Enum fields ride as u16 ordinals (world.fbs ChatChannel / ChatRejectReason) so this
// POD API carries no generated-enum dependency, exactly like the status fields above:
//   ChatChannel{SAY=0,YELL=1,WHISPER=2,ZONE=3};
//   ChatRejectReason{NOT_IN_WORLD=0,RATE_LIMITED=1,EMPTY=2,TOO_LONG=3,NO_TARGET=4,
//                    TARGET_OFFLINE=5}.
// ---------------------------------------------------------------------------

// CHAT_MESSAGE (C→S): send one chat line. `target` is meaningful only for WHISPER (the
// recipient's character name, case-insensitive) and ignored for other channels; `text`
// is the message body (a '.'-prefixed body is a GM command the server intercepts).
struct ChatMessage {
    std::uint16_t channel = 0;  // ChatChannel (default SAY)
    std::string target;         // WHISPER recipient name (empty otherwise)
    std::string text;           // the message body
};
Bytes encode_chat_message(const ChatMessage& in);
std::optional<ChatMessage> decode_chat_message(const Bytes& buf);  // test/mock symmetry

// CHAT_DELIVER (S→C): a chat line delivered to this client. `sender_guid` is the
// author's entity guid (0 = SYSTEM — the client renders it as a "System" line rather
// than a player line / bubble); `sender_name` is the display name; `channel` tells the
// client how it was routed (SAY/YELL float a bubble over sender_guid's entity).
struct ChatDeliver {
    std::uint16_t channel = 0;  // ChatChannel
    std::uint64_t sender_guid = 0;
    std::string sender_name;
    std::string text;
};
Bytes encode_chat_deliver(const ChatDeliver& in);  // test/mock symmetry (client decodes)
std::optional<ChatDeliver> decode_chat_deliver(const Bytes& buf);

// CHAT_REJECTED (S→C): the server refused a ChatMessage. `channel` echoes the attempted
// channel; `reason` is world.fbs ChatRejectReason; `target` echoes the attempted WHISPER
// target (empty otherwise) so the client can surface "X is not online".
struct ChatRejected {
    std::uint16_t channel = 0;  // ChatChannel
    std::uint16_t reason = 0;   // ChatRejectReason
    std::string target;
};
Bytes encode_chat_rejected(const ChatRejected& in);  // test/mock symmetry (client decodes)
std::optional<ChatRejected> decode_chat_rejected(const Bytes& buf);

}  // namespace meridian::clientnet::codec

#endif  // MERIDIAN_CLIENTNET_CODEC_H
